  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [message, setMessage] = useState<string | null>(null);

  const handleGoogleLogin = async () => {
    setLoading(true);
    setError(null);
    try {
        const { error } = await supabase.auth.signInWithOAuth({
            provider: 'google',
            options: {
                queryParams: {
                    access_type: 'offline',
                    prompt: 'consent',
                },
                redirectTo: window.location.origin
            },
        });
        if (error) throw error;
    } catch (error: any) {
        console.error("Google login error:", error);
        if (error.message === 'Failed to fetch') {
            setError('Bloqueio de rede detectado. Desative AdBlockers/VPN e tente novamente.');
        } else {
            setError(error.message || 'Erro ao conectar com Google. Verifique se o provedor está habilitado no Supabase.');
        }
        setLoading(false);
    }
  };

  const handleAuth = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setLoading(true);
    setError(null);
    setMessage(null);

    try {
        if (password.length < 6) {
            throw new Error('A senha precisa ter no mínimo 6 caracteres.');
        }

        if (isLogin) {
            const { error } = await supabase.auth.signInWithPassword({
                email: email,
                password: password,
            });

            if (error) throw error;
        } else {
            const { data, error } = await supabase.auth.signUp({
                email: email,
                password: password,
                options: {
                    data: {
                        full_name: name,
                    }
                }
            });

            if (error) throw error;
            setMessage('Cadastro realizado! Verifique seu email para confirmação.');
        }
    } catch (error: any) {
        console.error("Auth error:", error);
        // Tratamento específico para "Failed to fetch" que é comum em problemas de CORS/Rede/AdBlock
        if (error.message === 'Failed to fetch' || error.message.includes('NetworkError')) {
            setError('Conexão bloqueada. Por favor, desative AdBlockers ou VPN e tente novamente.');
