// A chave de API DEVE ser obtida de process.env.API_KEY.
let ai;
try {
    if (!process.env.API_KEY) {
        console.error("CRITICAL: Gemini API Key is missing from environment variables.");
    } else {
        ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    }
} catch (e) {
    console.error("Failed to initialize GoogleGenAI client:", e.message);
}

// --- PROXY MANUAL PARA SUPABASE (Resolve CORS em Produção) ---
// Redireciona chamadas de /supaproxy/* para a URL real do Supabase
app.all('/supaproxy/*', async (req, res) => {
    const targetBase = 'https://uflheoknbopcgmzyjbft.supabase.co';
    const path = req.url.replace('/supaproxy', '');
    const targetUrl = targetBase + path;

    try {
        const fetchOptions = {
            method: req.method,
            headers: {
                'apikey': req.headers.apikey,
                'authorization': req.headers.authorization,
                'content-type': req.headers['content-type'] || 'application/json',
                // Mascara a origem para o Supabase aceitar
                'Origin': targetBase
            }
        };

        // Se tiver corpo e não for GET/HEAD, repassa o JSON
        if (['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method) && req.body && Object.keys(req.body).length > 0) {
            fetchOptions.body = JSON.stringify(req.body);
        }

        const response = await fetch(targetUrl, fetchOptions);

        // Repassa o status e headers relevantes
        res.status(response.status);
        res.setHeader('Content-Type', response.headers.get('content-type') || 'application/json');

        const data = await response.text();
        res.send(data);

    } catch (err) {
        console.error("Supabase Proxy Error:", err);
        res.status(502).json({ error: "Erro de conexão com o banco de dados (Proxy)." });
    }
});

