        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false); // Inicializa sem sync

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // Fetch de Dados (Background Sync) - NÃO BLOQUEANTE
    useEffect(() => {
        if (!user) return;
        const fetchData = async () => {
            // Usamos isSyncing para dar feedback sutil (ex: na sidebar) se necessário.
            setIsSyncing(true);

            try {
                // OTIMIZAÇÃO CRÍTICA (Resource Exhaustion Fix):
                // NÃO selecionamos a coluna 'data' (JSON pesado) na listagem inicial.
                // Isso evita o erro de "Exhausting multiple resources" no Supabase Nano.
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') // SEM 'data'
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null // Lazy Load: Iniciamos sem dados pesados
                    })));
                }
            } catch (err) { console.error('Background sync failed', err); } 
            finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };
        fetchData();
    }, [user?.id]);

    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;
            // No modo Lazy Load, o Dashboard histórico fica limitado aos dados já carregados na memória
            // ou apenas à sessão ativa, para evitar crash.
            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);
    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            // LAZY LOAD LOGIC: Busca o conteúdo 'data' apenas se ele estiver vazio
            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    // Atualiza cache local
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
            reconciliation.setMatchResults(validResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
            });
            reconciliation.setHasActiveSession(true); 
            setActiveView('reports'); 
        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    const confirmManualIdentification = useCallback((transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);
        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);
            reconciliation.closeManualIdentify(); showToast('Identificação realizada.', 'success');
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback((transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);
            }
        });
        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            // Se for uma edição de match reverso, precisamos remover o ID fantasma
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }
        showToast("Edição salva com sucesso.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import React, { useContext, useState, useMemo } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EmptyState } from '../components/EmptyState';
import { 
    DocumentDuplicateIcon, 
    SearchIcon, 
    TrashIcon, 
    EyeIcon, 
    PencilIcon, 
    FloppyDiskIcon, 
    XCircleIcon, 
    XMarkIcon, 
    ChevronUpIcon, 
    ChevronDownIcon,
    TableCellsIcon,
    CircleStackIcon
} from '../components/Icons';
import { Language, SavedReport } from '../types';

const formatDate = (isoString: string, language: Language) => {
    return new Date(isoString).toLocaleString(language, {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
};

type SortKey = 'name' | 'createdAt' | 'recordCount';
type SortDirection = 'asc' | 'desc';

export const SavedReportsView: React.FC = () => {
    const { savedReports, viewSavedReport, openDeleteConfirmation, updateSavedReportName, maxSavedReports } = useContext(AppContext);
    const { setActiveView } = useUI();
    const { t, language } = useTranslation();

    // State
    const [searchQuery, setSearchQuery] = useState('');
    const [editingReportId, setEditingReportId] = useState<string | null>(null);
    const [editName, setEditName] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ 
        key: 'createdAt', 
        direction: 'desc' 
    });

    // Filter & Sort Logic
    const processedReports = useMemo(() => {
        let result = [...savedReports];

        // 1. Filter
        if (searchQuery) {
            const lowerQ = searchQuery.toLowerCase();
            result = result.filter(report =>
                report.name.toLowerCase().includes(lowerQ)
            );
        }

        // 2. Sort
        result.sort((a, b) => {
            let valA: any = a[sortConfig.key];
            let valB: any = b[sortConfig.key];

            // Special handling for dates
            if (sortConfig.key === 'createdAt') {
                valA = new Date(valA).getTime();
                valB = new Date(valB).getTime();
            }

            // String comparison for names
            if (typeof valA === 'string') {
                valA = valA.toLowerCase();
                valB = valB.toLowerCase();
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });

        return result;
    }, [savedReports, searchQuery, sortConfig]);

    // Handlers
    const handleSort = (key: SortKey) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc'
        }));
    };

    const handleStartEdit = (report: SavedReport) => {
        setEditingReportId(report.id);
        setEditName(report.name);
    };

    const handleCancelEdit = () => {
        setEditingReportId(null);
        setEditName('');
    };

    const handleSaveEdit = (reportId: string) => {
        if (editName.trim()) {
            updateSavedReportName(reportId, editName);
            handleCancelEdit();
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent, reportId: string) => {
        if (e.key === 'Enter') handleSaveEdit(reportId);
        else if (e.key === 'Escape') handleCancelEdit();
    };

    // Sort Icon Helper
    const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
        if (sortConfig.key !== columnKey) return <ChevronDownIcon className="w-3 h-3 opacity-30 group-hover:opacity-60" />;
        return sortConfig.direction === 'asc' 
            ? <ChevronUpIcon className="w-3 h-3 text-brand-blue" />
            : <ChevronDownIcon className="w-3 h-3 text-brand-blue" />;
    };

    // Storage Calculation
    const usagePercent = Math.min(100, (savedReports.length / maxSavedReports) * 100);
    let storageColor = "bg-emerald-500";
    if (usagePercent > 80) storageColor = "bg-red-500";
    else if (usagePercent > 50) storageColor = "bg-amber-500";

    if (savedReports.length === 0) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState
                    icon={<DocumentDuplicateIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />}
                    title={t('savedReports.empty.title')}
                    message={t('savedReports.empty.message')}
                    action={{
                        text: t('empty.dashboard.action'), 
                        onClick: () => setActiveView('upload'),
                    }}
                />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-4 pb-2">
            {/* Header Compacto */}
            <div className="flex-shrink-0 flex flex-col md:flex-row md:items-end justify-between gap-3 px-1">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500 dark:text-slate-400">
                        <TableCellsIcon className="w-5 h-5" />
                    </div>
                    <div>
                        <h2 className="text-xl font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('savedReports.title')}</h2>
                        <p className="text-slate-500 dark:text-slate-400 text-[10px] mt-1 font-medium">
                            Histórico e backups de conciliações.
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-4 flex-1 justify-end">
                    {/* Storage Meter - New Component */}
                    <div className="hidden md:flex flex-col w-32 xl:w-40 mr-2 bg-slate-50 dark:bg-slate-800/50 p-2 rounded-xl border border-slate-100 dark:border-slate-700/50">
                        <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">
                            <span className="flex items-center gap-1"><CircleStackIcon className="w-3 h-3" /> Espaço</span>
                            <span className={usagePercent > 80 ? 'text-red-500' : 'text-emerald-500'}>{Math.round(usagePercent)}%</span>
                        </div>
                        <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                            <div
                                className={`h-full rounded-full transition-all duration-1000 ease-out ${storageColor}`}
                                style={{ width: `${usagePercent}%` }}
                            ></div>
                        </div>
                        <div className="text-[8px] text-right mt-1 text-slate-400 font-medium">
                            {savedReports.length} / {maxSavedReports} usados
                        </div>
                    </div>

                    {/* Barra de Busca */}
                    <div className="relative w-full md:w-64">
                        <SearchIcon className="w-3.5 h-3.5 text-slate-400 absolute top-1/2 left-3 -translate-y-1/2" />
                        <input
                            type="text"
                            placeholder={t('savedReports.search')}
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            className="pl-9 pr-8 py-2 block w-full rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-brand-graphite dark:text-slate-200 text-xs font-bold shadow-sm focus:border-brand-blue focus:ring-brand-blue transition-all outline-none placeholder:text-slate-400 placeholder:font-medium"
                        />
                        {searchQuery && (
                            <button onClick={() => setSearchQuery('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                                <XMarkIcon className="h-3 w-3" />
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Tabela estilo Planilha */}
            <div className="flex-1 bg-white dark:bg-slate-800 rounded-[1.5rem] shadow-card border border-slate-100 dark:border-slate-700 overflow-hidden flex flex-col">
                <div className="flex-1 overflow-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-50/80 dark:bg-slate-900/50 sticky top-0 backdrop-blur-sm z-10 border-b border-slate-100 dark:border-slate-700">
                            <tr>
                                <th className="px-6 py-3 w-[45%]">
                                    <button onClick={() => handleSort('name')} className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none">
                                        Nome do Relatório
                                        <SortIcon columnKey="name" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 w-[20%]">
                                    <button onClick={() => handleSort('createdAt')} className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none">
                                        Criado em
                                        <SortIcon columnKey="createdAt" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 w-[15%] text-center">
                                    <button onClick={() => handleSort('recordCount')} className="flex items-center justify-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none w-full">
                                        Registros
                                        <SortIcon columnKey="recordCount" />
                                    </button>
                                </th>
                                <th className="px-6 py-3 w-[20%] text-center text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                    Ações
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-700/50">
                            {processedReports.length > 0 ? (
                                processedReports.map((report) => {
                                    const isEditing = editingReportId === report.id;
                                    return (
                                        <tr 
                                            key={report.id} 
                                            className="group hover:bg-blue-50/30 dark:hover:bg-blue-900/10 transition-colors"
                                        >
                                            <td className="px-6 py-3">
                                                <div className="flex items-center gap-3">
                                                    <div className="p-2 bg-blue-50 dark:bg-blue-900/20 text-brand-blue rounded-lg">
                                                        <DocumentDuplicateIcon className="w-4 h-4" />
                                                    </div>

                                                    {isEditing ? (
                                                        <div className="flex items-center gap-2 flex-1">
                                                            <input 
                                                                type="text" 
                                                                value={editName} 
                                                                onChange={(e) => setEditName(e.target.value)}
                                                                onKeyDown={(e) => handleKeyDown(e, report.id)}
                                                                autoFocus
                                                                className="w-full text-sm font-bold text-brand-graphite dark:text-white bg-white dark:bg-slate-900 border border-brand-blue rounded-lg px-3 py-1.5 focus:ring-2 focus:ring-brand-blue/20 outline-none shadow-sm"
                                                            />
                                                            <button
                                                                onClick={() => handleSaveEdit(report.id)}
                                                                className="p-1.5 rounded-lg text-emerald-600 bg-emerald-50 hover:bg-emerald-100 transition-colors"
                                                                title="Salvar"
                                                            >
                                                                <FloppyDiskIcon className="w-4 h-4" />
                                                            </button>
                                                            <button
                                                                onClick={handleCancelEdit}
                                                                className="p-1.5 rounded-lg text-red-500 bg-red-50 hover:bg-red-100 transition-colors"
                                                                title="Cancelar"
                                                            >
                                                                <XCircleIcon className="w-4 h-4" />
                                                            </button>
                                                        </div>
                                                    ) : (
                                                        <div className="flex items-center gap-2 group/edit relative max-w-full">
                                                            <span className="text-sm font-bold text-slate-700 dark:text-slate-200 truncate cursor-default">
                                                                {report.name}
                                                            </span>
                                                            <button 
                                                                onClick={() => handleStartEdit(report)}
                                                                className="opacity-0 group-hover/edit:opacity-100 p-1 text-slate-400 hover:text-brand-blue transition-opacity"
                                                                title="Renomear"
                                                            >
                                                                <PencilIcon className="w-3 h-3" />
                                                            </button>
                                                        </div>
                                                    )}
                                                </div>
                                            </td>

                                            <td className="px-6 py-3 text-xs font-medium text-slate-500 dark:text-slate-400 font-mono">
                                                {formatDate(report.createdAt, language)}
                                            </td>

                                            <td className="px-6 py-3 text-center">
                                                <span className="inline-flex items-center justify-center px-2.5 py-0.5 rounded-full text-[10px] font-bold bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600">
                                                    {report.recordCount}
                                                </span>
                                            </td>

                                            <td className="px-6 py-3">
                                                <div className="flex items-center justify-center gap-2 opacity-80 group-hover:opacity-100 transition-opacity">
                                                    <button
                                                        onClick={() => viewSavedReport(report.id)}
                                                        className="flex items-center gap-1.5 px-3 py-1.5 text-[10px] font-bold text-white bg-gradient-to-r from-brand-blue to-indigo-600 hover:from-blue-600 hover:to-indigo-700 rounded-full shadow-md shadow-blue-500/20 hover:-translate-y-0.5 transition-all active:scale-95"
                                                    >
                                                        <EyeIcon className="w-3 h-3" />
                                                        Abrir
                                                    </button>
                                                    <button
                                                        onClick={() => openDeleteConfirmation({ type: 'report-saved', id: report.id, name: report.name })}
                                                        className="p-1.5 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                                                        title="Excluir"
                                                    >
                                                        <TrashIcon className="w-4 h-4" />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={4} className="py-20 text-center">
                                        <div className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500">
                                            <SearchIcon className="w-10 h-10 mb-2 opacity-50" />
                                            <p className="text-xs font-bold">{t('common.noResults')}</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

import React, { useContext, useState, useMemo } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EmptyState } from '../components/EmptyState';
import { 
    DocumentDuplicateIcon, 
    SearchIcon, 
    TrashIcon, 
    EyeIcon, 
    PencilIcon, 
    FloppyDiskIcon, 
    XCircleIcon, 
    XMarkIcon, 
    ChevronUpIcon, 
    ChevronDownIcon,
    TableCellsIcon,
    CircleStackIcon,
    CalendarIcon,
    ChartBarIcon
} from '../components/Icons';
import { Language, SavedReport } from '../types';

const formatDate = (isoString: string, language: Language) => {
    return new Date(isoString).toLocaleString(language, {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
};

type SortKey = 'name' | 'createdAt' | 'recordCount';
type SortDirection = 'asc' | 'desc';

export const SavedReportsView: React.FC = () => {
    const { savedReports, viewSavedReport, openDeleteConfirmation, updateSavedReportName, maxSavedReports } = useContext(AppContext);
    const { setActiveView } = useUI();
    const { t, language } = useTranslation();

    // State
    const [searchQuery, setSearchQuery] = useState('');
    const [editingReportId, setEditingReportId] = useState<string | null>(null);
    const [editName, setEditName] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: SortKey; direction: SortDirection }>({ 
        key: 'createdAt', 
        direction: 'desc' 
    });

    // Filter & Sort Logic
    const processedReports = useMemo(() => {
        let result = [...savedReports];

        // 1. Filter
        if (searchQuery) {
            const lowerQ = searchQuery.toLowerCase();
            result = result.filter(report =>
                report.name.toLowerCase().includes(lowerQ)
            );
        }

        // 2. Sort
        result.sort((a, b) => {
            let valA: any = a[sortConfig.key];
            let valB: any = b[sortConfig.key];

            // Special handling for dates
            if (sortConfig.key === 'createdAt') {
                valA = new Date(valA).getTime();
                valB = new Date(valB).getTime();
            }

            // String comparison for names
            if (typeof valA === 'string') {
                valA = valA.toLowerCase();
                valB = valB.toLowerCase();
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });

        return result;
    }, [savedReports, searchQuery, sortConfig]);

    // Handlers
    const handleSort = (key: SortKey) => {
        setSortConfig(current => ({
            key,
            direction: current.key === key && current.direction === 'desc' ? 'asc' : 'desc'
        }));
    };

    const handleStartEdit = (report: SavedReport) => {
        setEditingReportId(report.id);
        setEditName(report.name);
    };

    const handleCancelEdit = () => {
        setEditingReportId(null);
        setEditName('');
    };

    const handleSaveEdit = (reportId: string) => {
        if (editName.trim()) {
            updateSavedReportName(reportId, editName);
            handleCancelEdit();
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent, reportId: string) => {
        if (e.key === 'Enter') handleSaveEdit(reportId);
        else if (e.key === 'Escape') handleCancelEdit();
    };

    // Sort Icon Helper
    const SortIcon = ({ columnKey }: { columnKey: SortKey }) => {
        if (sortConfig.key !== columnKey) return <ChevronDownIcon className="w-3 h-3 opacity-30 group-hover:opacity-60" />;
        return sortConfig.direction === 'asc' 
            ? <ChevronUpIcon className="w-3 h-3 text-brand-blue" />
            : <ChevronDownIcon className="w-3 h-3 text-brand-blue" />;
    };

    // Storage Calculation
    const usagePercent = Math.min(100, (savedReports.length / maxSavedReports) * 100);
    let storageColor = "bg-emerald-500";
    if (usagePercent > 80) storageColor = "bg-red-500";
    else if (usagePercent > 50) storageColor = "bg-amber-500";

    if (savedReports.length === 0) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState
                    icon={<DocumentDuplicateIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />}
                    title={t('savedReports.empty.title')}
                    message={t('savedReports.empty.message')}
                    action={{
                        text: t('empty.dashboard.action'), 
                        onClick: () => setActiveView('upload'),
                    }}
                />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-4 pb-2">
            {/* Header Compacto */}
            <div className="flex-shrink-0 flex flex-col md:flex-row md:items-end justify-between gap-3 px-1">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl text-slate-500 dark:text-slate-400">
                        <TableCellsIcon className="w-5 h-5" />
                    </div>
                    <div>
                        <h2 className="text-xl font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('savedReports.title')}</h2>
                        <p className="text-slate-500 dark:text-slate-400 text-[10px] mt-1 font-medium">
                            Histórico e backups de conciliações.
                        </p>
                    </div>
                </div>

                <div className="flex items-center gap-4 flex-1 justify-end">
                    {/* Storage Meter - New Component */}
                    <div className="hidden md:flex flex-col w-32 xl:w-40 mr-2 bg-slate-50 dark:bg-slate-800/50 p-2 rounded-xl border border-slate-100 dark:border-slate-700/50">
                        <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-wider text-slate-400 mb-1.5">
                            <span className="flex items-center gap-1"><CircleStackIcon className="w-3 h-3" /> Espaço</span>
                            <span className={usagePercent > 80 ? 'text-red-500' : 'text-emerald-500'}>{Math.round(usagePercent)}%</span>
                        </div>
                        <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                            <div
                                className={`h-full rounded-full transition-all duration-1000 ease-out ${storageColor}`}
                                style={{ width: `${usagePercent}%` }}
                            ></div>
                        </div>
                        <div className="text-[8px] text-right mt-1 text-slate-400 font-medium">
                            {savedReports.length} / {maxSavedReports} usados
                        </div>
                    </div>

                    {/* Barra de Busca */}
                    <div className="relative w-full md:w-64">
                        <SearchIcon className="w-3.5 h-3.5 text-slate-400 absolute top-1/2 left-3 -translate-y-1/2" />
                        <input
                            type="text"
                            placeholder={t('savedReports.search')}
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            className="pl-9 pr-8 py-2 block w-full rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-brand-graphite dark:text-slate-200 text-xs font-bold shadow-sm focus:border-brand-blue focus:ring-brand-blue transition-all outline-none placeholder:text-slate-400 placeholder:font-medium"
                        />
                        {searchQuery && (
                            <button onClick={() => setSearchQuery('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                                <XMarkIcon className="h-3 w-3" />
                            </button>
                        )}
                    </div>
                </div>
            </div>

            {/* Tabela com Visual de Cards / Lançar Dados */}
            <div className="flex-1 bg-white dark:bg-slate-800 rounded-[1.5rem] shadow-card border border-slate-100 dark:border-slate-700 overflow-hidden flex flex-col">
                <div className="flex-1 overflow-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead className="bg-slate-50/80 dark:bg-slate-900/50 sticky top-0 backdrop-blur-sm z-10 border-b border-slate-100 dark:border-slate-700">
                            <tr>
                                <th className="px-6 py-4 w-[45%]">
                                    <button onClick={() => handleSort('name')} className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none">
                                        Nome do Relatório
                                        <SortIcon columnKey="name" />
                                    </button>
                                </th>
                                <th className="px-6 py-4 w-[20%]">
                                    <button onClick={() => handleSort('createdAt')} className="flex items-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none">
                                        Criado em
                                        <SortIcon columnKey="createdAt" />
                                    </button>
                                </th>
                                <th className="px-6 py-4 w-[15%] text-center">
                                    <button onClick={() => handleSort('recordCount')} className="flex items-center justify-center gap-1.5 text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest group focus:outline-none w-full">
                                        Registros
                                        <SortIcon columnKey="recordCount" />
                                    </button>
                                </th>
                                <th className="px-6 py-4 w-[20%] text-center text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">
                                    Ações
                                </th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50 dark:divide-slate-700/50">
                            {processedReports.length > 0 ? (
                                processedReports.map((report) => {
                                    const isEditing = editingReportId === report.id;
                                    return (
                                        <tr 
                                            key={report.id} 
                                            className="group hover:bg-slate-50/50 dark:hover:bg-slate-700/20 transition-all duration-300"
                                        >
                                            <td className="px-6 py-3">
                                                <div className="flex items-center gap-3">
                                                    {/* Ícone Estilizado Igual ao Upload View */}
                                                    <div className="w-10 h-10 rounded-xl bg-blue-50 dark:bg-blue-900/20 text-brand-blue border border-blue-100 dark:border-blue-800 flex items-center justify-center shrink-0 shadow-sm group-hover:scale-105 transition-transform duration-300">
                                                        <DocumentDuplicateIcon className="w-5 h-5 stroke-[1.5]" />
                                                    </div>

                                                    {isEditing ? (
                                                        <div className="flex items-center gap-2 flex-1">
                                                            <input 
                                                                type="text" 
                                                                value={editName} 
                                                                onChange={(e) => setEditName(e.target.value)}
                                                                onKeyDown={(e) => handleKeyDown(e, report.id)}
                                                                autoFocus
                                                                className="w-full text-sm font-bold text-brand-graphite dark:text-white bg-white dark:bg-slate-900 border border-brand-blue rounded-lg px-3 py-2 focus:ring-2 focus:ring-brand-blue/20 outline-none shadow-sm"
                                                            />
                                                            <button
                                                                onClick={() => handleSaveEdit(report.id)}
                                                                className="p-2 rounded-lg text-emerald-600 bg-emerald-50 hover:bg-emerald-100 transition-colors"
                                                                title="Salvar"
                                                            >
                                                                <FloppyDiskIcon className="w-4 h-4" />
                                                            </button>
                                                            <button
                                                                onClick={handleCancelEdit}
                                                                className="p-2 rounded-lg text-red-500 bg-red-50 hover:bg-red-100 transition-colors"
                                                                title="Cancelar"
                                                            >
                                                                <XCircleIcon className="w-4 h-4" />
                                                            </button>
                                                        </div>
                                                    ) : (
                                                        <div className="flex flex-col min-w-0 group/edit relative pr-6">
                                                            <div className="flex items-center gap-2">
                                                                <span className="text-sm font-bold text-slate-800 dark:text-slate-100 truncate cursor-default group-hover:text-brand-blue transition-colors">
                                                                    {report.name}
                                                                </span>
                                                                <button 
                                                                    onClick={() => handleStartEdit(report)}
                                                                    className="opacity-0 group-hover/edit:opacity-100 p-1 text-slate-400 hover:text-brand-blue transition-all"
                                                                    title="Renomear"
                                                                >
                                                                    <PencilIcon className="w-3 h-3" />
                                                                </button>
                                                            </div>
                                                            <span className="text-[10px] text-slate-400 dark:text-slate-500 font-medium truncate">
                                                                ID: {report.id.substring(0, 12)}...
                                                            </span>
                                                        </div>
                                                    )}
                                                </div>
                                            </td>

                                            <td className="px-6 py-3">
                                                <div className="flex items-center gap-2 text-slate-500 dark:text-slate-400">
                                                    <CalendarIcon className="w-3.5 h-3.5" />
                                                    <span className="text-xs font-bold font-mono">
                                                        {formatDate(report.createdAt, language)}
                                                    </span>
                                                </div>
                                            </td>

                                            <td className="px-6 py-3 text-center">
                                                <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold bg-slate-100 dark:bg-slate-700/50 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600">
                                                    <ChartBarIcon className="w-3 h-3 text-slate-400" />
                                                    {report.recordCount}
                                                </span>
                                            </td>

                                            <td className="px-6 py-3">
                                                <div className="flex items-center justify-center gap-3">
                                                    <button
                                                        onClick={() => viewSavedReport(report.id)}
                                                        className="flex items-center gap-1.5 px-4 py-2 text-[10px] font-bold text-white bg-gradient-to-r from-brand-blue to-indigo-600 hover:from-blue-600 hover:to-indigo-700 rounded-full shadow-md shadow-blue-500/20 hover:-translate-y-0.5 transition-all active:scale-95 uppercase tracking-wide"
                                                    >
                                                        <EyeIcon className="w-3.5 h-3.5" />
                                                        Abrir
                                                    </button>
                                                    <button
                                                        onClick={() => openDeleteConfirmation({ type: 'report-saved', id: report.id, name: report.name })}
                                                        className="p-2 rounded-full text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 transition-all hover:scale-110"
                                                        title="Excluir"
                                                    >
                                                        <TrashIcon className="w-4 h-4 stroke-[2]" />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={4} className="py-20 text-center">
                                        <div className="flex flex-col items-center justify-center text-slate-400 dark:text-slate-500">
                                            <SearchIcon className="w-12 h-12 mb-3 opacity-20" />
                                            <p className="text-sm font-bold">{t('common.noResults')}</p>
                                            <p className="text-xs mt-1 opacity-70">Tente ajustar sua busca.</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};
